output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT(SUM(?numGames) AS ?total) WHERE {
  ?series wdt:P31 wd:Q2966447 ; wdt:P585 ?date ; wdt:P2139 ?numGames .
  {
    ?series wdt:P154 wd:Q334634 ; wdt:P153 wd:Q650840
  } UNION {
    ?series wdt:P154 wd:Q650840 ; wdt:P153 wd:Q334634
  }
  BIND(YEAR(?date) AS ?year)
  FILTER(?year IN(1977 , 1978 , 2008 , 2009))
}

